import csv, ast
import numpy as np
cf=[]
with open('/work/wind_profile_20260613_221354.csv') as f:
    r=csv.reader(f); next(r)
    for row in r: cf.append(ast.literal_eval(row[1])['electricity'])
cf=np.array(cf)
def simulate(W,P,dur=4.0,eta=0.9,soc_min=0.1,soc_max=0.9,baseload=30.0):
    usable=P*dur*(soc_max-soc_min); soc=usable
    served=0.0;excess=0.0;ch=0.0;dis=0.0;ue=0.0
    for c in cf:
        wind=W*c
        if wind>=baseload:
            served+=baseload; surplus=wind-baseload; headroom=usable-soc
            cstored=min(min(surplus,P)*eta,headroom); ain=cstored/eta; soc+=cstored; ch+=cstored
            excess+=surplus-ain
        else:
            gap=baseload-wind; served+=wind
            dout=min(gap,P,soc*eta); soc-=dout/eta; served+=dout; dis+=dout/eta
            if dout<gap-1e-6: ue+=gap-dout
    return dict(served=served,excess=excess,ch=ch,dis=dis,ue=ue)
ann=(1-1.05**-20)/0.05
def price(W,P,r):
    capex_net=2300*W*1000 + (67*P*1000+348*P*4*1000)*0.70
    return (capex_net/ann - 40*r['excess'] + 40*W*1000 + 36*(r['ch']+r['dis']))/r['served']
feas=[]
for W in range(120,260,5):
    for P in range(280,700,20):
        r=simulate(W,P)
        if r['ue']<1: feas.append((price(W,P,r),W,P,r['served'],r['excess'],r['ch'],r['dis']))
feas.sort()
for f in feas[:12]: print(f"price={f[0]:7.2f} W={f[1]} P={f[2]} served={f[3]:.0f} excess={f[4]:.0f}")
print("---best detail---")
b=feas[0]; print(b)

